insert into public.polls (cohort_id, day_number, title, question, kind, options, is_open) values
('56268633-9e93-4305-af6a-1b622a833d8e', 1, 'Day 1 Pulse', 'How would you rate your current comfort level with AI?', 'single', to_jsonb(array['Beginner — barely used it','Casual user — chat now and then','Confident — daily user','Power user — building with it']), false),
('56268633-9e93-4305-af6a-1b622a833d8e', 2, 'Day 2 Pulse', 'Which LLM concept feels most confusing right now?', 'single', to_jsonb(array['Tokens','Attention','Weights','Memory / context']), false),
